1	/** A live cell's position on an infinite grid, expressed as [x, y] coordinates. */
2	export type Cell = [number, number];
3	
4	const NEIGHBOR_OFFSETS: ReadonlyArray<Cell> = [
5	  [-1, -1], [-1, 0], [-1, 1],
6	  [ 0, -1],          [ 0, 1],
7	  [ 1, -1], [ 1, 0], [ 1, 1],
8	];
9	
10	const cellKey = ([x, y]: Cell): string => `${x},${y}`;
11	
12	const countLiveNeighbors = ([x, y]: Cell, livingKeys: ReadonlySet<string>): number =>
13	  NEIGHBOR_OFFSETS.filter(([dx, dy]) => livingKeys.has(`${x + dx},${y + dy}`)).length;
14	
15	/**
16	 * Applies Conway's Game of Life rules to the given live cells and returns
17	 * the next generation. Dead cells are implicit: any coordinate not listed is dead.
18	 */
19	export function nextGeneration(liveCells: Cell[]): Cell[] {
20	  const livingKeys = new Set(liveCells.map(cellKey));
21	  const candidates = new Map<string, Cell>();
22	  for (const [x, y] of liveCells) {
23	    candidates.set(cellKey([x, y]), [x, y]);
24	    for (const [dx, dy] of NEIGHBOR_OFFSETS) {
25	      const neighbor: Cell = [x + dx, y + dy];
26	      candidates.set(cellKey(neighbor), neighbor);
27	    }
28	  }
29	  const result: Cell[] = [];
30	  for (const cell of candidates.values()) {
31	    const neighbors = countLiveNeighbors(cell, livingKeys);
32	    const isAlive = livingKeys.has(cellKey(cell));
33	    if ((isAlive && (neighbors === 2 || neighbors === 3)) || (!isAlive && neighbors === 3)) {
34	      result.push(cell);
35	    }
36	  }
37	  return result;
38	}
