1	import { describe, it, expect } from "vitest";
2	import { nextGeneration } from "./game-of-life.js";
3	
4	describe("Game of Life - nextGeneration", () => {
5	  it("empty grid stays empty — [] → []", () => {
6	    expect(nextGeneration([])).toEqual([]);
7	  });
8	  it("single live cell dies (underpopulation) — [(0,0)] → []", () => {
9	    expect(nextGeneration([[0, 0]])).toEqual([]);
10	  });
11	  it("two adjacent live cells both die (underpopulation, 1 neighbor each) — [(0,1),(1,1)] → []", () => {
12	    expect(nextGeneration([[0, 1], [1, 1]])).toEqual([]);
13	  });
14	  it("block still life remains unchanged — [(0,0),(1,0),(0,1),(1,1)] → same", () => {
15	    const block: [number, number][] = [[0, 0], [1, 0], [0, 1], [1, 1]];
16	    expect(new Set(nextGeneration(block).map((c) => c.join(",")))).toEqual(
17	      new Set(block.map((c) => c.join(","))),
18	    );
19	  });
20	  it("live cell with 4 neighbors dies (overpopulation) — center of full 3x3 dies", () => {
21	    const input: [number, number][] = [
22	      [0, 0], [1, 0], [2, 0],
23	              [1, 1],
24	      [0, 2], [1, 2], [2, 2],
25	    ];
26	    const keys = new Set(nextGeneration(input).map((c) => c.join(",")));
27	    expect(keys.has("1,1")).toBe(false);
28	  });
29	  it("dead cell with exactly 3 neighbors becomes alive (reproduction) — L-shape produces block", () => {
30	    const input: [number, number][] = [[0, 0], [1, 0], [0, 1]];
31	    const expected = new Set(["0,0", "1,0", "0,1", "1,1"]);
32	    const actual = new Set(nextGeneration(input).map((c) => c.join(",")));
33	    expect(actual).toEqual(expected);
34	  });
