/**
 * Applies Conway's Game of Life rules to the given live cells and returns
 * the next generation. Dead cells are implicit: any coordinate not listed is dead.
 */
export function nextGeneration(liveCells: Cell[]): Cell[] {
  const livingKeys = new Set(liveCells.map(cellKey));
  const candidates = new Map<string, Cell>();
  for (const [x, y] of liveCells) {
    candidates.set(cellKey([x, y]), [x, y]);
    for (const [dx, dy] of NEIGHBOR_OFFSETS) {
      const neighbor: Cell = [x + dx, y + dy];
      candidates.set(cellKey(neighbor), neighbor);
    }
  }
  const result: Cell[] = [];
  for (const cell of candidates.values()) {
    const neighbors = countLiveNeighbors(cell, livingKeys);
    const isAlive = livingKeys.has(cellKey(cell));
    if ((isAlive && (neighbors === 2 || neighbors === 3)) || (!isAlive && neighbors === 3)) {
      result.push(cell);
    }
  }
  return result;
}

