const countLiveNeighbors = ([x, y]: Cell, livingKeys: ReadonlySet<string>): number =>
  NEIGHBOR_OFFSETS.filter(([dx, dy]) => livingKeys.has(`${x + dx},${y + dy}`)).length;

const neighborsOf = ([x, y]: Cell): Cell[] =>
  NEIGHBOR_OFFSETS.map(([dx, dy]) => [x + dx, y + dy]);

const survivesOrIsBorn = (isAlive: boolean, liveNeighbors: number): boolean =>
  liveNeighbors === 3 || (isAlive && liveNeighbors === 2);

/**
 * Applies Conway's Game of Life rules to the given live cells and returns
 * the next generation. Dead cells are implicit: any coordinate not listed is dead.
 */
export function nextGeneration(liveCells: Cell[]): Cell[] {
  const livingKeys = new Set(liveCells.map(cellKey));
  const candidates = new Map<string, Cell>();
  for (const cell of liveCells) {
    candidates.set(cellKey(cell), cell);
    for (const neighbor of neighborsOf(cell)) {
      candidates.set(cellKey(neighbor), neighbor);
    }
  }
  const survivors: Cell[] = [];
  for (const [key, cell] of candidates) {
    if (survivesOrIsBorn(livingKeys.has(key), countLiveNeighbors(cell, livingKeys))) {
      survivors.push(cell);
    }
  }
  return survivors;
}
